    for i in range(len(sorted_l) - 2):
        target = -sorted_l[i]
        left = i + 1
        right = len(sorted_l) - 1
        while left < right:
            current_sum = sorted_l[left] + sorted_l[right]
            if current_sum == target:
                return True
            elif current_sum < target:
                left += 1
